import React, { Component } from "react";
import "./Levels.css";
import Dot from "./Dot/Dot";
import { isMobile } from "react-device-detect";

class Levels extends Component {
  state = {
    colors: ["#555555", "#555555", "#555555"],
  };

  componentDidMount = () => {
    if (isMobile) {
      this.setState(() => ({
        colors: ["#59DB28", "#F6B921", "#CA0424"],
      }));
    }
  };

  setDefaultColor = () => {
    this.setState(() => ({
      colors: ["#555555", "#555555", "#555555"],
    }));
  };

  onHover = (index) => () => {
    switch (index) {
      case 0:
        this.setState(() => ({
          colors: ["#59DB28", "#555555", "#555555"],
        }));
        break;
      case 1:
        this.setState(() => ({
          colors: ["#F6B921", "#F6B921", "#555555"],
        }));
        break;
      case 2:
        this.setState(() => ({
          colors: ["#CA0424", "#CA0424", "#CA0424"],
        }));
        break;
      default:
        return;
    }
  };

  render() {
    return (
      <div className="levels__wrapper">
        {this.state.colors.map((color, index) => (
          <Dot
            color={color}
            blur={this.setDefaultColor}
            hover={this.onHover(index)}
            press={() => this.props.onSelect(index)}
            key={index}
          />
        ))}
      </div>
    );
  }
}

export default Levels;
